3_real_world_example.code:
const user = {
  name: 'Alice',
  loginCount: 0,

  // This is a method!
  login: function() {
    console.log('Logging in...');
    // Using 'this' allows the method to access sibling properties
    this.loginCount++; 
  },

  // Modern shorthand syntax for methods (ES6)
  logout() {
    console.log('Logging out...');
  }
};

user.login();
console.log(user.loginCount); // 1

